CREATE VIEW `ads_short_video_payorder_view` (`dt` COMMENT "createtime分区", `product_id` COMMENT "产品id 6833海外短剧", `id` COMMENT "自增id", `type`, `user_id` COMMENT "用户id", `used` COMMENT "是否执行", `order_id` COMMENT "订单id", `flag` COMMENT "标识", `create_time` COMMENT "创建时间", `get_time` COMMENT "获取时间", `item_count` COMMENT "金额数", `system_type` COMMENT "系统类型", `receive_date` COMMENT "被接收时间", `mt` COMMENT "终端", `coupon_id` COMMENT "礼券id", `package_id` COMMENT "存放充值页面来源", `shop_item` COMMENT "充值类型", `extinfo` COMMENT "信息", `vip_expire_time` COMMENT "充值订阅卡时，过期时间", `real_money` COMMENT "给的阅币数", `give_money` COMMENT "暂时无用", `amount` COMMENT "暂时无用", `prod_id` COMMENT "暂时无用", `pay_config_id` COMMENT "充值项的id，可能不准确", `corever` COMMENT "包体", `unique_guid` COMMENT "用户设备id", `test_flag` COMMENT "是否是测试号充值（0正式，1测试）", `buy_token` COMMENT "购买时候的google的token", `base_amount` COMMENT "分成后的数量", `version` COMMENT "购买时，用户客户端的版本号", `subpay_type` COMMENT "充值渠道", `gift_money` COMMENT "充值赠送的礼券数(可能不准确)", `order_init_time` COMMENT "用户订单创建时间", `cooorder_extinfo` COMMENT "合作方订单扩展", `custom_data` COMMENT "自定义数据，透传，json格式", `corever2` COMMENT "当前core")
COMMENT "海外短剧-用户充值表" AS SELECT `ods`.`a`.`dt`, 6833 AS `product_id`, `ods`.`a`.`id`, `ods`.`a`.`type`, `ods`.`a`.`userid` AS `user_id`, `ods`.`a`.`used`, `ods`.`a`.`orderid` AS `order_id`, `ods`.`a`.`flag`, `ods`.`a`.`createtime` AS `create_time`, `ods`.`a`.`gettime` AS `get_time`, `ods`.`a`.`itemcount` AS `item_count`, `ods`.`a`.`systemtype` AS `system_type`, `ods`.`a`.`receivedate` AS `receive_date`, `ods`.`a`.`mt`, `ods`.`a`.`couponid` AS `coupon_id`, `ods`.`a`.`packageid` AS `package_id`, `ods`.`a`.`shopitem` AS `shop_item`, `ods`.`a`.`extinfo`, `ods`.`a`.`vipexpiretime` AS `vip_expire_time`, `ods`.`a`.`realmoney` AS `real_money`, `ods`.`a`.`givemoney` AS `give_money`, `ods`.`a`.`amount`, `ods`.`a`.`prodid` AS `prod_id`, `ods`.`a`.`payconfigid` AS `pay_config_id`, `ods`.`a`.`corever`, `ods`.`a`.`uniqueguid` AS `unique_guid`, `ods`.`a`.`testflag` AS `test_flag`, `ods`.`a`.`buytoken` AS `buy_token`, `ods`.`a`.`baseamount` AS `base_amount`, `ods`.`a`.`version`, `ods`.`a`.`subpaytype` AS `subpay_type`, `ods`.`a`.`giftmoney` AS `gift_money`, `ods`.`a`.`orderinittime` AS `order_init_time`, `ods`.`a`.`cooorderextinfo` AS `cooorder_extinfo`, `ods`.`a`.`customdata` AS `custom_data`, `dim`.`b`.`corever2`
FROM `ods`.`ods_tidb_short_video_payorder` AS `a` LEFT OUTER JOIN `dim`.`dim_short_video_user_accountinfo` AS `b` ON `ods`.`a`.`userid` = `dim`.`b`.`user_id`;